    correct: { core: {}, scenario: {} },
    robust: { core: {}, scenario: {} },
    performant: { core: {}, scenario: {} },
    production: { core: {}, scenario: {} },
  };

  let blocked = false;
  let highestGate = 0;
  let scoreSum = 0;

