#!/usr/bin/env python3
"""
Reconciliation job: compares transaction counts across Postgres, Redpanda, and ClickHouse.
Reports any drift (count mismatches) between the three systems.
"""
import os
import sys
from urllib.parse import urlparse

# Postgres
def get_postgres_count(postgres_url: str) -> int:
    import psycopg
    parsed = urlparse(postgres_url)
    conn = psycopg.connect(
        host=parsed.hostname or "localhost",
        port=parsed.port or 5432,
        dbname=parsed.path.lstrip("/") or "postgres",
        user=parsed.username or "postgres",
        password=parsed.password,
    )
    try:
        with conn.cursor() as cur:
            cur.execute("SELECT count(*) FROM app.transactions")
            return int(cur.fetchone()[0])
    finally:
        conn.close()


def get_redpanda_count(broker: str, topic: str = "transactions") -> int:
    from kafka import KafkaConsumer
    from kafka.structs import TopicPartition

    consumer = KafkaConsumer(
        bootstrap_servers=broker.split(","),
        consumer_timeout_ms=2000,
    )
    try:
        partitions = consumer.partitions_for_topic(topic)
        if not partitions:
            return 0
        topic_partitions = [TopicPartition(topic, p) for p in partitions]
        end_offsets = consumer.end_offsets(topic_partitions)
        return sum(end_offsets.get(tp, 0) for tp in topic_partitions)
    finally:
        consumer.close()


def get_clickhouse_count(clickhouse_url: str) -> int:
    import urllib.request

    url = clickhouse_url.rstrip("/") + "/?query="
    query = "SELECT count() AS n FROM analytics.transactions FORMAT JSONEachRow"
    req = urllib.request.Request(url + urllib.parse.quote(query))
    with urllib.request.urlopen(req, timeout=10) as resp:
        import json
        body = resp.read().decode()
        rows = [json.loads(line) for line in body.strip().split("\n") if line]
        return int(rows[0]["n"]) if rows else 0


def main() -> int:
    postgres_url = os.environ.get("POSTGRES_URL")
    redpanda_broker = os.environ.get("REDPANDA_BROKER")
    clickhouse_url = os.environ.get("CLICKHOUSE_URL", "http://localhost:8123")

    errors = []
    if not postgres_url:
        errors.append("POSTGRES_URL not set")
    if not redpanda_broker:
        errors.append("REDPANDA_BROKER not set")
    if not clickhouse_url:
        errors.append("CLICKHOUSE_URL not set")

    if errors:
        print("ERROR: " + "; ".join(errors), file=sys.stderr)
        return 1

    pg_count = ch_count = rp_count = None
    drift = []

    try:
        pg_count = get_postgres_count(postgres_url)
    except Exception as e:
        drift.append(f"Postgres: FAILED - {e}")
        pg_count = -1

    try:
        rp_count = get_redpanda_count(redpanda_broker)
    except Exception as e:
        drift.append(f"Redpanda: FAILED - {e}")
        rp_count = -1

    try:
        ch_count = get_clickhouse_count(clickhouse_url)
    except Exception as e:
        drift.append(f"ClickHouse: FAILED - {e}")
        ch_count = -1

    counts = {"postgres": pg_count, "redpanda": rp_count, "clickhouse": ch_count}
    valid = {k: v for k, v in counts.items() if v >= 0}

    if len(valid) < 2:
        print("ERROR: Could not retrieve counts from at least 2 systems.", file=sys.stderr)
        for d in drift:
            print(f"  {d}", file=sys.stderr)
        return 1

    # Report counts
    print("Reconciliation Report")
    print("=" * 50)
    print(f"  Postgres:   {pg_count if pg_count >= 0 else 'N/A'}")
    print(f"  Redpanda:   {rp_count if rp_count >= 0 else 'N/A'}")
    print(f"  ClickHouse: {ch_count if ch_count >= 0 else 'N/A'}")
    print()

    # Detect drift
    if pg_count is not None and pg_count >= 0 and rp_count is not None and rp_count >= 0:
        if pg_count != rp_count:
            drift.append(f"Postgres ({pg_count}) != Redpanda ({rp_count})")
    if pg_count is not None and pg_count >= 0 and ch_count is not None and ch_count >= 0:
        if pg_count != ch_count:
            drift.append(f"Postgres ({pg_count}) != ClickHouse ({ch_count})")
    if rp_count is not None and rp_count >= 0 and ch_count is not None and ch_count >= 0:
        if rp_count != ch_count:
            drift.append(f"Redpanda ({rp_count}) != ClickHouse ({ch_count})")

    if drift:
        print("DRIFT DETECTED:")
        for d in drift:
            print(f"  - {d}")
        return 1

    print("OK: All counts match.")
    return 0


if __name__ == "__main__":
    sys.exit(main())

